// Retry helper with screenshot on failure
async function retryWithScreenshot(action, maxRetries = 3) {
    let lastError;
    for (let i = 0; i < maxRetries; i++) {
        try {
            await action();
            return 'passed';
        } catch (e) {
            lastError = e;
            await page.screenshot({ path: `failure-attempt-${i+1}.png` });
        }
    }
    throw lastError;
}

// Use the retry helper
await retryWithScreenshot(async () => {
    await page.click('#action');
    await expect(page.locator('#result')).toContainText('attempts');
});

challenges.solution:
async function retryWithScreenshot(action, maxRetries = 3) {
    for (let i = 0; i < maxRetries; i++) {
        try {
            await action();
            return 'passed';
        } catch (e) {
            await page.screenshot({ path: 'failure.png' });
        }
    }
    return 'failed';
}
await retryWithScreenshot(async () => {
    await page.click('#action');
    await expect(page.locator('#result')).toContainText('Success');
});
